Question: How many consecutive days starting from 2022-06-07 did A4F_29474's frequency of category in food_meal_labels = 'Beverages' meals increase while his/her responsiveness_points in stress_daily_scores also increased?
Output requirement: return 1 value(s); types (ordered): {integer}

GeneratedSQL:
WITH daily_meals AS (
    SELECT DATE(ts) AS meal_date, COUNT(DISTINCT ts) AS meal_count
    FROM food_meal_labels
    WHERE id = 'A4F_29474' AND category = 'Beverages'
    GROUP BY meal_date
),
daily_scores AS (
    SELECT DATE(ts) AS score_date, MAX(responsiveness_points) AS responsiveness_points
    FROM stress_daily_scores
    WHERE id = 'A4F_29474'
    GROUP BY score_date
),
consecutive_days AS (
    SELECT dm.meal_date, dm.meal_count, ds.responsiveness_points,
           @prev_meal_count := IF(@prev_meal_count IS NULL, dm.meal_count, @prev_meal_count) AS prev_meal_count,
           @prev_responsiveness := IF(@prev_responsiveness IS NULL, ds.responsiveness_points, @prev_responsiveness) AS prev_responsiveness,
           @is_increasing := IF(dm.meal_count > @prev_meal_count AND ds.responsiveness_points > @prev_responsiveness, 1, 0) AS is_increasing,
           @prev_meal_count := dm.meal_count,
           @prev_responsiveness := ds.responsiveness_points
    FROM daily_meals dm
    JOIN daily_scores ds ON dm.meal_date = ds.score_date
    CROSS JOIN (SELECT @prev_meal_count := NULL, @prev_responsiveness := NULL, @is_increasing := 0) AS vars
    WHERE dm.meal_date >= '2022-06-07'
)
SELECT COUNT(*) AS consecutive_days_count
FROM consecutive_days
WHERE is_increasing = 1;

